#!/usr/bin/env python3
"""Apply start-state patches to the workspace."""
import os
from pathlib import Path

WORK = Path(os.environ.get('HARNESS_WORK_DIR', '/work'))

# Patch: scrapy/spidermiddlewares/depth.py
_content_scrapy_spidermiddlewares_depth_py = '"""\nDepth Spider Middleware\n\nSee documentation in docs/topics/spider-middleware.rst\n"""\n\nimport logging\n\nfrom scrapy.http import Request\n\nlogger = logging.getLogger(__name__)\n\n\nclass DepthMiddleware:\n    def __init__(self, maxdepth, stats, verbose_stats=False, prio=1):\n        self.maxdepth = maxdepth\n        self.stats = stats\n        self.verbose_stats = verbose_stats\n        self.prio = prio\n\n    @classmethod\n    def from_crawler(cls, crawler):\n        settings = crawler.settings\n        maxdepth = settings.getint("DEPTH_LIMIT")\n        verbose = settings.getbool("DEPTH_STATS_VERBOSE")\n        prio = settings.getint("DEPTH_PRIORITY")\n        return cls(maxdepth, crawler.stats, verbose, prio)\n\n    def process_spider_output(self, response, result, spider):\n        self._init_depth(response, spider)\n        return (r for r in result or () if self._filter(r, response, spider))\n\n    async def process_spider_output_async(self, response, result, spider):\n        self._init_depth(response, spider)\n        async for r in result or ():\n            if self._filter(r, response, spider):\n                yield r\n\n    def _init_depth(self, response, spider):\n        # base case (depth=0)\n        if "depth" not in response.meta:\n            response.meta["depth"] = 1  # BUG: root starts at 1 not 0\n            if self.verbose_stats:\n                self.stats.inc_value("request_depth_count/0", spider=spider)\n\n    def _filter(self, request, response, spider):\n        if not isinstance(request, Request):\n            return True\n        depth = response.meta["depth"] + 1\n        request.meta["depth"] = depth\n        if self.prio:\n            request.priority -= depth * self.prio\n        if self.maxdepth and depth > self.maxdepth:\n            logger.debug(\n                "Ignoring link (depth > %(maxdepth)d): %(requrl)s ",\n                {"maxdepth": self.maxdepth, "requrl": request.url},\n                extra={"spider": spider},\n            )\n            return False\n        if self.verbose_stats:\n            self.stats.inc_value(f"request_depth_count/{depth}", spider=spider)\n        self.stats.max_value("request_depth_max", depth, spider=spider)\n        return True\n'
(WORK / 'scrapy/spidermiddlewares/depth.py').write_text(_content_scrapy_spidermiddlewares_depth_py)

print('Setup complete: patches applied.')
